import axios from 'axios';

/**
 * Generate real-time search suggestions using Google Autocomplete API
 */
export async function getSuggestions(query) {
  try {
    if (!query) return [];

    console.log(`💡 Fetching real-time suggestions for: ${query}`);

    // Call Google's open autocomplete endpoint (no API key required)
    const response = await axios.get('http://suggestqueries.google.com/complete/search', {
      params: {
        client: 'chrome',
        q: query,
        hl: 'en'
      }
    });

    // The response is an array where the second element contains the suggestions
    // e.g., ["iphone", ["iphone 15", "iphone 17 pro", "iphone 13"]]
    if (response.data && Array.isArray(response.data[1])) {
      return response.data[1].slice(0, 8); // Return top 8 suggestions
    }

    return [];
  } catch (error) {
    console.error('❌ Suggestions error:', error.message);
    
    // Fallback to basic mock suggestions if the API fails
    const mockSuggestions = [
      'iPhone 16', 'iPhone 17 Pro', 'Samsung Galaxy S24', 
      'MacBook Pro M3', 'Sony Headphones', 'Nike Shoes'
    ];
    
    return mockSuggestions.filter(s => 
      s.toLowerCase().includes(query.toLowerCase())
    ).slice(0, 5);
  }
}
